96	interface ClaimEntry {
97	  itemIndex: number;
98	  damageAmount: number;
99	}
100	
101	function calculateItemReimbursement(item: PolicyItem, damageAmount: number): number {
102	  if (item.dragonMaterial) {
103	    return damageAmount;
104	  }
105	  if (item.enchantment && item.enchantment >= 8) {
106	    return damageAmount * 0.5;
107	  }
108	  return 0;
109	}
110	
111	export function processClaim(policy: unknown, claims: unknown): number {
112	  const policyItems = policy as PolicyItem[];
113	  const claimEntries = claims as ClaimEntry[];
114	
115	  // Calculate policy cap: 2x the total item value
116	  const totalItemValue = policyItems.reduce((sum, item) => sum + item.baseCost, 0);
117	  const policyCap = totalItemValue * 2;
118	
119	  let totalReimbursement = 0;
120	  for (const claim of claimEntries) {
121	    const item = policyItems[claim.itemIndex];
122	    totalReimbursement += calculateItemReimbursement(item, claim.damageAmount);
123	  }
124	
125	  // Cap the reimbursement at the policy maximum
126	  return Math.min(totalReimbursement, policyCap);
127	}
